{"type": "post", "post": {"team": "tech_team", "channel": "system_uptime", "user": "daniel_kim", "message": "John, Tuesday at 10 works for me. Let's finalize that and I'll send out a calendar invite.", "created_at": 1620500000005}}
{"type": "post", "post": {"team": "management_team", "channel": "strategic_planning", "user": "jane_doe", "message": "Remember, our goal for the next quarter is to improve customer experience. Let's keep that in mind while planning.", "created_at": 1620500000006}}
